196→          ))}
197→        </ScrollView>
198→      </View>
199→
200→      {/* Feed */}
201→      <FlatList
202→        data={posts}
203→        onRefresh={onRefresh}
204→        refreshing={refreshing}
205→        onEndReachedThreshold={0.25}
206→        onEndReached={() => {
