138→                  color: statusFilter === filter.value ? '#FFFFFF' : colors.textMuted,
139→                  fontWeight: statusFilter === filter.value ? '700' : 'normal',
140→                },
141→              ]}>
142→              {filter.label}
143→            </Text>
144→          </Pressable>
145→        ))}
146→      </View>
147→
148→      {storiesQuery.isLoading ? (
149→        <View style={styles.loading}>
150→          <ActivityIndicator color={colors.accentAmber} />
151→          <Text style={[styles.metaHint, {color: colors.textMuted}]}>Loading stories...</Text>
152→        </View>
153→      ) : (
154→        <FlatList
155→          data={stories}
156→          keyExtractor={item => item.id}
157→          onEndReachedThreshold={0.3}
158→          onEndReached={() => {
159→            if (storiesQuery.hasNextPage && !storiesQuery.isFetchingNextPage) {
160→              storiesQuery.fetchNextPage();
161→            }
162→          }}
163→          ListEmptyComponent={<Text style={[styles.metaHint, {color: colors.textMuted}]}>No stories found.</Text>}
164→          renderItem={({item}) => (
165→            <StoryCard
166→              story={item}
167→              onPress={() => navigation.navigate('StoryDetail', {storyId: item.id})}
168→            />
169→          )}
170→          ListFooterComponent={
171→            storiesQuery.isFetchingNextPage ? (
172→              <View style={styles.loadingMore}>
173→                <ActivityIndicator color={colors.accentAmber} />
174→              </View>
175→            ) : null
176→          }
177→        />
178→      )}
179→    </Screen>
180→  );
181→}
